def topological_sort(n, edges):
    graph = [[] for _ in range(n)]
    for u, v in edges:
        graph[u].append(v)

    visited = [0] * n
    ordering = []

    def dfs(node):
        if visited[node] == -1:
            return False
        if visited[node] == 1:
            return True
        visited[node] = -1
        for neighbor in graph[node]:
            if not dfs(neighbor):
                return False
        visited[node] = 1
        ordering.append(node)
        return True

    for node in range(n):
        if visited[node] == 0 and not dfs(node):
            return []

    return ordering[::-1]
